function Projects() {
  const projects = [
    {
      title: "CRM App",
      desc: "Full Stack CRM with JWT Authentication & Dashboard",
    },
    {
      title: "Real-time Chat App",
      desc: "Socket.io based live messaging app",
    },
    {
      title: "E-commerce Backend",
      desc: "Cart system with Admin Panel",
    },
  ];

  return (
    <section id="projects" className="p-20 bg-gray-900">
      <h2 className="text-3xl font-bold text-green-400 mb-6">Projects</h2>
      <div className="grid md:grid-cols-3 gap-6">
        {projects.map((project, index) => (
          <div
            key={index}
            className="bg-gray-800 p-6 rounded-lg hover:scale-105 transition"
          >
            <h3 className="text-xl font-bold mb-2">{project.title}</h3>
            <p>{project.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
}

export default Projects;
